(self.webpackChunkvuepress_blog=self.webpackChunkvuepress_blog||[]).push([[6237],{2509:(e,l,s)=>{"use strict";s.r(l),s.d(l,{data:()=>t});const t={key:"v-4d1ef650",path:"/pages/self-daily/school/university5/",title:"",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:3,title:"回忆是一种奇妙的感觉",slug:"回忆是一种奇妙的感觉",children:[]},{level:3,title:"开学第一天",slug:"开学第一天",children:[]}],filePathRelative:"pages/self-daily/school/university5/README.md",git:{updatedTime:1719927556e3,contributors:[{name:"guilin.li",email:"1344714332@qq.com",commits:2},{name:"COOKIES-LGL",email:"1344714332@qq.com",commits:1}]}}},3074:(e,l,s)=>{"use strict";s.r(l),s.d(l,{default:()=>c});var t=s(6252);const a=(0,t.Wm)("h3",{id:"回忆是一种奇妙的感觉"},[(0,t.Wm)("a",{class:"header-anchor",href:"#回忆是一种奇妙的感觉"},"#"),(0,t.Uk)(" 回忆是一种奇妙的感觉")],-1),i=(0,t.Wm)("p",null,"   岁月匆匆,来不及让人留恋,在这匆匆世界里或许只有文字里才能找寻到那份安静,祥和.",-1),r=(0,t.Wm)("h3",{id:"开学第一天"},[(0,t.Wm)("a",{class:"header-anchor",href:"#开学第一天"},"#"),(0,t.Uk)(" 开学第一天")],-1),n=(0,t.Wm)("p",null,"大学开学第一天, 我很开心, 因为我知道, 我会在这里度过一个美好的大学生活.第一次出省是读小学的时候去了我妈打工的地方浙江嘉兴，第二次出省是去了福建莆田和我姐去旅游，这是我第三次出省，我爸和我一路绿皮火车，做了12个小时，来到了无锡，那是2016年九月，无锡天气很好，给我的感觉也很发达，但是火车站那个时候还是旧的在改造，火车站破破烂烂的。一下火车，出站的时候就看到了学校来迎接新生的学生会成员，他们把我和我爸带上了一辆大巴，大约半个小时我们就坐满了一车的人，我们都是新生和家属。在路上，大巴上还有讲解的学生在给我们介绍无锡，介绍无锡的风光，无锡的历史。在蠡湖大桥，看到了蠡湖歌剧院。第一次进校门从北门进去的，一个很大的牌匾写着江南第一学府。大门下摆满了鲜花，还有迎接新生的标语。我们去食堂吃了饭，去学校逛了一天。",-1),c={render:function(e,l){return(0,t.wg)(),(0,t.j4)(t.HY,null,[a,i,r,n],64)}}}}]);